public class TestClass {
    public void testMethod() {
        Object mock1 = new Object();
        Object mock2 = new Object();

        when(mock1.someMethod()).thenReturn(true);
        when(mock1.anotherMethod()).thenReturn(false);

        when(mock2.someMethod()).thenReturn(true);
        when(mock2.anotherMethod()).thenReturn(false);
    }
}
